				continue
			}
			if assign.StationsLen == 0 && assignIdx >= dispatch.AssignsLen {
				dispatch.AssignsLen = assignIdx + 1
			}
			savedStates[assignIdx] = savedState{
				Cost:           assign.Cost,
				StationsLen:    assign.StationsLen,
				StationCurrent: assign.StationCurrent,
			}
			success := assign.AddShip(total_ship+orderIdx, oris[orderIdx], dess[orderIdx])
			if success {
				oldCost := assign.Cost
				assign.GenRoute()
				newCost := assign.Cost
				delta := newCost - oldCost
				var distSaving float64 = 0
				if assign.StationsLen > 2 {
