		fallbackNewAssignBackup := Assign{}
		savedStates := make([]Assign, dispatch.AssignsLen+1)
		for i := 0; i < dispatch.AssignsLen; i++ {
			savedStates[i] = dispatch.Assigns[i]
		}
		maxTryAssign := dispatch.AssignsLen + 1
		if maxTryAssign > MAXASSIGNS {
			maxTryAssign = MAXASSIGNS
		}
		for tryAssignIdx := 0; tryAssignIdx < maxTryAssign; tryAssignIdx++ {
			isNewAssign := tryAssignIdx >= dispatch.AssignsLen
			if isNewAssign {
				if tryAssignIdx >= MAXASSIGNS {
					continue
				}
				savedStates[tryAssignIdx] = dispatch.Assigns[tryAssignIdx]
			}
			currentAssign := &dispatch.Assigns[tryAssignIdx]
			if !currentAssign.AddShip(total_ship+shipIdx, oris[shipIdx], dess[shipIdx]) {
				if isNewAssign {
					fallbackNewAssignIdx = tryAssignIdx
					fallbackNewAssignBackup = *currentAssign
				}
				*currentAssign = savedStates[tryAssignIdx]
				continue
			}
			oldCost := currentAssign.Cost
